import signal
import langgraph

def timeout_handler(signum, frame):
    raise TimeoutError('Graph execution exceeded 30s - potential cycle detected')

def detect_cycles(graph, input):
    signal.signal(signal.SIGALRM, timeout_handler)
    signal.alarm(30)
    try:
        result = graph.invoke(input)
        signal.alarm(0)
        return {'status': 'passed', 'result': result}
    except TimeoutError:
        return {'status': 'failed', 'error': 'Infinite loop detected'}

