from langgraph.checkpoint.sqlite import SqliteSaver
from typing import get_type_hints

def detect_schema_drift(graph, checkpoint_db='checkpoints.db'):
    checkpointer = SqliteSaver.from_conn_string(checkpoint_db)

    # Get current schema
    current_schema = get_type_hints(graph.State)

    # Sample existing checkpoints
    config = {'configurable': {'thread_id': 'test-1'}}
    try:
        existing = checkpointer.get(tuple())
        if existing:
            old_state = json.loads(existing['channel_states'])
            missing_fields = set(current_schema.keys()) - set(old_state.keys())
            return {
                'drift_detected': bool(missing_fields),
                'missing_fields': list(missing_fields)
            }
    except Exception as e:
        return {'deserialization_error': str(e)}
    return {'drift_detected': False}

