from typing import Annotated, TypedDict
from langgraph.graph import StateGraph, END
from langgraph.graph.message import add_messages

class StateWithVisited(TypedDict):
    messages: Annotated[list, add_messages]
    visited_nodes: set

class NoCycleGraph(StateGraph):
    def __init__(self):
        super().__init__(StateWithVisited)

    def safe_add_node(self, name, action):
        def safe_action(state):
            if name in state.get('visited_nodes', set()):
                return {'visited_nodes': state['visited_nodes'], 'messages': ['Cycle detected, terminating']}

            state['visited_nodes'] = state.get('visited_nodes', set()) | {name}
            return action(state)

        self.add_node(name, safe_action)

