from typing import TypedDict, List, Optional, Any
from langgraph.graph import StateGraph

def safe_merge(a: dict, b: dict) -> dict:
    '''Merge two state dicts with conflict resolution'''
    result = a.copy()
    for k, v in b.items():
        if k in result:
            if isinstance(result[k], list) and isinstance(v, list):
                result[k] = list(set(result[k] + v))  # Dedupe lists
            elif result[k] != v:
                result[f'{k}_conflict'] = [result[k], v]  # Flag conflicts
        else:
            result[k] = v
    return result

class SafeStateGraph(StateGraph):
    def add_conditional_edges(self, *args, **kwargs):
        def safe_router(state):
            # Ensure state is merge-safe before routing
            return self.conditional_router(state)
        super().add_conditional_edges(safe_router, *args, **kwargs)

